/**
 * Acquired Sandbox - local backend (zero dependencies)
 *
 * Uses only Node.js built-in modules, so there is nothing to `npm install`.
 * Holds your App ID / App Key, mints an access_token, proxies every request
 * to the Acquired test API, and receives/verifies webhooks (HMAC-SHA256).
 */
const http = require('http');
const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

const INDEX_HTML = Buffer.from("", 'base64').toString('utf8');

// ---------------------------------------------------------------------------
// Load .env (simple parser - no dependency needed)
// ---------------------------------------------------------------------------
function loadEnv() {
  const env = {};
  try {
    const raw = fs.readFileSync(path.join(__dirname, '.env'), 'utf8');
    raw.split(/\r?\n/).forEach((line) => {
      const m = line.match(/^\s*([A-Z0-9_]+)\s*=\s*(.*)\s*$/i);
      if (m && !line.trim().startsWith('#')) {
        let v = m[2];
        if ((v.startsWith('"') && v.endsWith('"')) || (v.startsWith("'") && v.endsWith("'"))) v = v.slice(1, -1);
        env[m[1]] = v;
      }
    });
  } catch (_) { /* no .env yet */ }
  return env;
}
const fileEnv = loadEnv();
const cfg = (k, d) => process.env[k] || fileEnv[k] || d;

const PORT = Number(cfg('PORT', '3000'));
const ENV = (cfg('ACQUIRED_ENV', 'test')).toLowerCase();
const API_BASE = ENV === 'production' ? 'https://api.acquired.com/v1' : 'https://test-api.acquired.com/v1';
const PAY_BASE = ENV === 'production' ? 'https://pay.acquired.com/v1' : 'https://test-pay.acquired.com/v1';
const APP_ID = cfg('ACQUIRED_APP_ID', '');
const APP_KEY = cfg('ACQUIRED_APP_KEY', '');
const SIGNING_KEY = cfg('ACQUIRED_SIGNING_KEY', '');
const PUBLIC_KEY = cfg('ACQUIRED_PUBLIC_KEY', '');
const DEFAULT_COMPANY_ID = cfg('ACQUIRED_COMPANY_ID', '');
const DEFAULT_MID = cfg('ACQUIRED_MID', '');
const ACCESS_PASSWORD = cfg('ACCESS_PASSWORD', ''); // if set, the whole site asks for a password

if (typeof fetch !== 'function') {
  console.error('This Node.js is too old (needs v18+). Please use the portable Node from start.command.');
  process.exit(1);
}

// ---------------------------------------------------------------------------
// Access token cache
// ---------------------------------------------------------------------------
let tokenCache = { token: null, expiresAt: 0 };
async function getToken(force) {
  const now = Date.now();
  if (!force && tokenCache.token && now < tokenCache.expiresAt - 30000) return tokenCache.token;
  if (!APP_ID || !APP_KEY) throw new Error('Missing ACQUIRED_APP_ID or ACQUIRED_APP_KEY in your .env file.');
  const res = await fetch(`${API_BASE}/login`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ app_id: APP_ID, app_key: APP_KEY }),
  });
  const data = await res.json().catch(() => ({}));
  if (!res.ok || !data.access_token) {
    const err = new Error(data.title || 'Login failed - check your App ID and App Key.');
    err.detail = data; err.statusCode = res.status;
    throw err;
  }
  tokenCache = { token: data.access_token, expiresAt: now + (data.expires_in || 3600) * 1000 };
  return tokenCache.token;
}

// ---------------------------------------------------------------------------
// Webhook store + verification
// ---------------------------------------------------------------------------
const webhookLog = [];
const MAX_WEBHOOKS = 200;
function verifyHash(rawBody, hashHeader) {
  if (!SIGNING_KEY) return { checked: false, valid: null, note: 'No signing key configured.' };
  if (!hashHeader) return { checked: true, valid: false, note: 'No Hash header on this webhook.' };
  const provided = String(hashHeader).split(',').map((h) => h.trim().toLowerCase());
  const candidates = new Set([rawBody, rawBody.replace(/\s+/g, '')]);
  try { candidates.add(JSON.stringify(JSON.parse(rawBody))); } catch (_) {}
  for (const c of candidates) {
    const computed = crypto.createHmac('sha256', SIGNING_KEY).update(c, 'utf8').digest('hex').toLowerCase();
    if (provided.includes(computed)) return { checked: true, valid: true, computed, note: 'Signature matches.' };
  }
  const computed = crypto.createHmac('sha256', SIGNING_KEY).update(rawBody, 'utf8').digest('hex').toLowerCase();
  return { checked: true, valid: false, computed, provided, note: 'No candidate hash matched the Hash header.' };
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------
function send(res, status, obj) {
  const body = JSON.stringify(obj);
  res.writeHead(status, { 'Content-Type': 'application/json' });
  res.end(body);
}
function readBody(req) {
  return new Promise((resolve) => {
    let data = '';
    req.on('data', (c) => { data += c; if (data.length > 4e6) req.destroy(); });
    req.on('end', () => resolve(data));
    req.on('error', () => resolve(data));
  });
}
const MIME = {
  '.html': 'text/html; charset=utf-8', '.css': 'text/css; charset=utf-8', '.js': 'text/javascript; charset=utf-8',
  '.json': 'application/json', '.svg': 'image/svg+xml', '.ico': 'image/x-icon', '.png': 'image/png',
};
function serveStatic(req, res, urlPath) {
  res.writeHead(200, { 'Content-Type': 'text/html; charset=utf-8' });
  res.end(INDEX_HTML);
}

// ---------------------------------------------------------------------------
// Server
// ---------------------------------------------------------------------------
const server = http.createServer(async (req, res) => {
  const url = req.url || '/';
  const method = req.method || 'GET';

  // Optional password gate (only active when ACCESS_PASSWORD is set - e.g. when hosted).
  if (ACCESS_PASSWORD) {
    const expected = 'Basic ' + Buffer.from('acquired:' + ACCESS_PASSWORD).toString('base64');
    if ((req.headers['authorization'] || '') !== expected) {
      res.writeHead(401, { 'WWW-Authenticate': 'Basic realm="Acquired Sandbox"', 'Content-Type': 'text/plain' });
      return res.end('Password required');
    }
  }

  try {
    if (url === '/api/config' && method === 'GET') {
      return send(res, 200, {
        env: ENV, api_base: API_BASE, pay_base: PAY_BASE, app_id: APP_ID, public_key: PUBLIC_KEY,
        company_id: DEFAULT_COMPANY_ID, mid: DEFAULT_MID,
        has_app_key: Boolean(APP_KEY), has_signing_key: Boolean(SIGNING_KEY),
      });
    }

    if (url === '/api/test-connection' && method === 'GET') {
      try { await getToken(true); return send(res, 200, { ok: true, message: 'Connected. Access token obtained successfully.' }); }
      catch (e) { return send(res, 502, { ok: false, message: e.message, detail: e.detail || null }); }
    }

    if (url === '/api/proxy' && method === 'POST') {
      const body = JSON.parse((await readBody(req)) || '{}');
      const { method: m = 'GET', path: apiPath, body: reqBody, company_id, mid } = body;
      if (!apiPath || !apiPath.startsWith('/')) return send(res, 400, { error: 'A "path" starting with "/" is required.' });
      let token;
      try { token = await getToken(); } catch (e) { return send(res, 502, { error: e.message, detail: e.detail || null, stage: 'login' }); }
      const headers = { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' };
      const companyId = company_id || DEFAULT_COMPANY_ID;
      const midVal = mid || DEFAULT_MID;
      if (companyId) headers['Company-Id'] = companyId;
      if (midVal) headers['Mid'] = midVal;
      const upstream = { method: String(m).toUpperCase(), headers };
      if (!['GET', 'HEAD'].includes(upstream.method) && reqBody != null) upstream.body = JSON.stringify(reqBody);
      const sent = { method: upstream.method, url: API_BASE + apiPath, headers: { ...headers, Authorization: 'Bearer <access_token>' }, body: upstream.body ? JSON.parse(upstream.body) : undefined };
      try {
        const up = await fetch(API_BASE + apiPath, upstream);
        const text = await up.text();
        let data; try { data = text ? JSON.parse(text) : null; } catch { data = text; }
        return send(res, 200, { ok: up.ok, status: up.status, statusText: up.statusText, data, sent });
      } catch (e) { return send(res, 502, { error: e.message, sent, stage: 'upstream' }); }
    }

    if (url === '/api/webhooks/incoming' && method === 'POST') {
      const raw = await readBody(req);
      const hashHeader = req.headers['hash'] || '';
      const verification = verifyHash(raw, hashHeader);
      let parsed; try { parsed = JSON.parse(raw); } catch { parsed = null; }
      const record = {
        id: crypto.randomUUID(), receivedAt: new Date().toISOString(),
        headers: { 'Company-Id': req.headers['company-id'] || null, 'Mid': req.headers['mid'] || null, 'Webhook-Version': req.headers['webhook-version'] || null, 'Hash': hashHeader || null, 'Content-Type': req.headers['content-type'] || null },
        webhook_type: parsed && parsed.webhook_type ? parsed.webhook_type : 'unknown',
        body: parsed, raw, verification,
      };
      webhookLog.push(record);
      if (webhookLog.length > MAX_WEBHOOKS) webhookLog.shift();
      return send(res, 200, { received: true });
    }

    if (url === '/api/webhooks' && method === 'GET') {
      return send(res, 200, { webhooks: [...webhookLog].reverse(), signing_key_configured: Boolean(SIGNING_KEY) });
    }
    if (url === '/api/webhooks/clear' && method === 'POST') { webhookLog.length = 0; return send(res, 200, { ok: true }); }
    if (url === '/api/webhooks/simulate' && method === 'POST') {
      const inBody = JSON.parse((await readBody(req)) || '{}');
      const b = inBody && inBody.body ? inBody.body : inBody;
      const raw = JSON.stringify(b);
      const hash = SIGNING_KEY ? crypto.createHmac('sha256', SIGNING_KEY).update(raw, 'utf8').digest('hex') : '';
      const record = {
        id: crypto.randomUUID(), receivedAt: new Date().toISOString(),
        headers: { 'Webhook-Version': '2', 'Hash': hash || null, 'Content-Type': 'application/json', simulated: true },
        webhook_type: b && b.webhook_type ? b.webhook_type : 'unknown', body: b, raw, verification: verifyHash(raw, hash), simulated: true,
      };
      webhookLog.push(record);
      if (webhookLog.length > MAX_WEBHOOKS) webhookLog.shift();
      return send(res, 200, { ok: true, record });
    }

    if (url.startsWith('/api/')) return send(res, 404, { error: 'Unknown endpoint' });

    // static
    return serveStatic(req, res, url);
  } catch (e) {
    return send(res, 500, { error: e.message });
  }
});

server.listen(PORT, () => {
  console.log('');
  console.log('  Acquired Sandbox is running');
  console.log(`  Environment : ${ENV}  (${API_BASE})`);
  console.log(`  Open        : http://localhost:${PORT}`);
  console.log(`  App Key set : ${APP_KEY ? 'yes' : 'NO - add it to your .env file'}`);
  console.log('');
});
